var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제 이름을 알고 있다는 건…….","JPN":"私の名前を知っているということは……","ENG":"So you know my name...","TWN":"你知道我的名字……？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군요. 당신도 그 사람들과 같은 곳에서 온 이방인인 모양이네요.","JPN":"そうですか、あなたもあの人たちと同じ世界から来た異邦人なのですね。","ENG":"I see. Then you must be an outsider from the same place as those people.","TWN":"原來如此。看來你也和那些人一樣，是來自同一個地方的異鄉人。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 사람들? 아, 미나 양을 말씀하는 건가요?","JPN":"あの人たち？　ああ、ミナさんのことですか？","ENG":"Those people? Ah, you mean Mina?","TWN":"那些人？啊，你是指米娜嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 미나 양과 같은 세계에서 온 것은 맞지만, 같은 목적으로 온 건 아닙니다.","JPN":"はは、ミナさんと同じ世界から来たのは確かですが、目的は違います。","ENG":"Haha, it's true that we're from the same world, but we didn't come here for the same reason.","TWN":"哈哈，我們的確來自同一個世界，但我們的目的並不相同。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제 목적은 <color=#ffd34c>당신</color>이거든요.","JPN":"僕の目的は<color=#ffd34c>あなた</color>ですから。","ENG":"My objective is <color=#ffd34c>you</color>.","TWN":"我的目的，是<color=#ffd34c>你</color>。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신의 목적이 저라고요?","JPN":"あなたの目的が私？","ENG":"I'm your objective?","TWN":"你的目的是我？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네, 이런저런 사정이 있어서요.","JPN":"ええ、色々事情がありましてね。","ENG":"Yes. There are various circumstances.","TWN":"對，因為一些原因。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"말로 설명하는 것보다는 이쪽이 빠르겠네요.","JPN":"言葉で説明するよりは、こっちのほうが手っ取り早いでしょう。","ENG":"It would be faster to show you than to explain it.","TWN":"與其用言語說明，不如直接讓你看看吧。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>테라브레인 단말 접속 확인.</color>","JPN":"<color=#ffd34c>テラブレイン端末接続確認。</color>","ENG":"<color=#ffd34c>Terrabrain terminal connection confirmed.</color>","TWN":"<color=#ffd34c>確認連接特拉大腦終端。</color>"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>경고. 단말의 해치를 개방하기 위해서는 2급 관리자 이상의 권한이 필요합니다.</color>","JPN":"<color=#ffd34c>警告。端末のハッチを開放するためには2級管理者以上の権限が必要です。</color>","ENG":"<color=#ffd34c>Warning. Class 2 Administrator authorization or higher is required to open the terminal hatch.</color>","TWN":"<color=#ffd34c>警告。開啟終端艙口需要二級管理者以上權限。</color>"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>코드를 입력해주십시오.</color>","JPN":"<color=#ffd34c>コードを入力してください。</color>","ENG":"<color=#ffd34c>Please enter the code.</color>","TWN":"<color=#ffd34c>請輸入代碼。</color>"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"검은 상자가 말을 하잖아? 이게 대체 뭐죠?","JPN":"黒い箱が言葉を？　これはいったい何なのですか？","ENG":"The black box is talking? What is this thing?","TWN":"黑色箱子在說話？這到底是什麼？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그런가. 리하르트의 시니어 코드로 단말을 잠가 둔 모양이군.","JPN":"そうか。リヒャルトのシニアコードで端末をロックしていたか。","ENG":"I see. It seems the terminal was locked with Richard's Senior Code.","TWN":"原來如此，用理查的資深代碼把終端鎖起來了啊。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"훗, 과연 마지막까지 용의주도하네. 하지만…….","JPN":"ふっ、最後まで用意周到だ。しかし……","ENG":"Heh, meticulous to the very end. But...","TWN":"呵，果然到最後一刻都很謹慎。不過……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>2급 관리자 나유빈 확인.</color>","JPN":"<color=#ffd34c>2級管理者イチノセ・カオルを確認。</color>","ENG":"<color=#ffd34c>Class 2 Administrator Na Yubin, confirmed.</color>","TWN":"<color=#ffd34c>確認二級管理者羅瑜斌。</color>"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>해치를 개방합니다.</color>","JPN":"<color=#ffd34c>ハッチを開放します。</color>","ENG":"<color=#ffd34c>Opening hatch.</color>","TWN":"<color=#ffd34c>艙口開啟。</color>"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"상자가 열렸어……?","JPN":"箱が開いた……？","ENG":"It opened...?","TWN":"箱子打開了……？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 설마 이게 <color=#ffd34c>다른 세계로 통하는 문</color>인가요……?","JPN":"では、まさかこれが<color=#ffd34c>別の世界に通じる扉</color>ですか……？","ENG":"Then... could this be a <color=#ffd34c>door to another world</color>...?","TWN":"那麼，難道這真的是通往<color=#ffd34c>其他世界的門</color>……？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"다른 세계로 통하는 문? 그게 무슨 말이죠?","JPN":"別の世界に通じる扉？　何を言っているんですか？","ENG":"A door to another world? What do you mean?","TWN":"通往其他世界的門？你這是什麼意思？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이야말로 무슨 말이죠?","JPN":"あなたこそ、何を言っているんですか？","ENG":"What do you mean, what do I mean?","TWN":"是我要問你這句話才對吧？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인은 이 유적이 다른 세계로 통하는 문이라고 했는데……?","JPN":"アバーラインは、この遺跡が別の世界に通じる扉だと言っていたのですが……","ENG":"Abberline said this ruin was a door to another world...","TWN":"艾伯林說這座遺跡是通往其他世界的門啊……？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"확실히… 세계를 넘나든다는 게 틀린 말은 아니지만, 이건 문 같은 게 아닙니다.","JPN":"確かに……世界を行き来するという点では概ね間違っていませんが、これは扉のようなものではありません。","ENG":"Well... it's not wrong to say it crosses worlds, but this isn't a door.","TWN":"確實……說它能跨越世界並不算錯，但這並不是什麼門。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이 단말기는 일종의 나침반 겉은 거죠. 함선을 안내하는.","JPN":"この端末は一種の羅針盤です。艦船を導くためのね。","ENG":"This terminal is more like a kind of compass. One that guides a ship.","TWN":"這台終端，更像是一種用來引導艦船的指南針。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"함선? 그럼, 이 유적이 배의 일부였다는 뜻인가요?","JPN":"艦船？　ではこの遺跡は船の一部だったということですか？","ENG":"A ship? Then does that mean this ruin was part of a ship?","TWN":"艦船？所以這座遺跡其實是船的一部分嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 이해가 빠르시네요.","JPN":"はは、理解が早いですね。","ENG":"Haha, you catch on quickly.","TWN":"哈哈，你理解得真快。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래요, 우리 세계는 이런 좌초된 함선을 <color=#ffd34c>로스트쉽</color>이라고 부릅니다.","JPN":"そう。僕たちの世界ではこのような座礁した艦船のことを<color=#ffd34c>ロストシップ</color>と呼んでいます。","ENG":"Yes. In our world, we call wrecked ships like this a <color=#ffd34c>Lost Ship</color>.","TWN":"沒錯。在我們的世界，這種擱淺的艦船被稱為<color=#ffd34c>失落之船</color>。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아마도 이 로스트쉽과 테라브레인은 관리자님께서 이 세계에 남겨둔 유산.","JPN":"おそらくこのロストシップとテラブレインは、管理者さんがこの世界に遺した遺産。","ENG":"This Lost Ship and the Terrabrain are probably legacies the Administrator left behind in this world.","TWN":"而這艘失落之船還有特拉大腦，大概就是管理者留在這個世界的遺產吧。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 당신에게 있어서, 이곳은…….","JPN":"そしてあなたにとって、ここは……","ENG":"And for you, this place is...","TWN":"而對你來說，這裡就是……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>모든 각본이 시작된 곳</color>이라고도 할 수 있겠죠.","JPN":"<color=#ffd34c>すべての脚本が始まった場所</color>と言えるでしょう。","ENG":"It could be called <color=#ffd34c>where all scripts began</color>.","TWN":"<color=#ffd34c>所有劇本開始的地方</color>。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"모든 각본이 시작된 곳……?","JPN":"すべての脚本が始まった場所……？","ENG":"Where all scripts began...?","TWN":"所有劇本開始的地方……？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"나무를 숨기려면, 숲에 숨긴다라… 역시 스완은 뛰어난 각본가네요.","JPN":"木を隠すなら森の中……スワンはやはり優れた脚本家です。","ENG":"Hide a tree in the forest... as expected of Swan, a brilliant scriptwriter.","TWN":"所謂要藏起一棵樹，就藏進森林中……史旺，你果然是個出色的編劇。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"타기리온의 클리파에 귀속된 고향 세계, 그것도 테라브레인이 있는 이 장소라면…….","JPN":"タギリオンのクリファに帰属する故郷の世界、しかもテラブレインがあるここは……","ENG":"If it's your home world bound to Thagirion's Qlipha, and a place with a Terrabrain...","TWN":"在歸屬於塔基里翁逆卡巴拉故鄉的世界，而且還是擁有特拉大腦的這個地方……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그녀에게 들키지 않게, <color=#ffd34c>퍼즐 조각</color>을 숨겨 놓기에는 최적의 장소로군요.","JPN":"彼女にバレず<color=#ffd34c>パズルのピース</color>を隠すにはうってつけの場所です。","ENG":"It's the perfect place to hide a <color=#ffd34c>piece of the puzzle</color> without her noticing.","TWN":"要不被她察覺，藏起<color=#ffd34c>拼圖碎片</color>，這裡確實是最合適的地點。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"클리파? 테라브레인? 퍼즐 조각? 아까부터 무슨 말씀을 하시는 거죠?","JPN":"クリファ？　テラブレイン？　パズルのピース？　先程から何の話ですか？","ENG":"Qlipha? Terrabrain? Piece of the puzzle? What are you talking about?","TWN":"逆卡巴拉？特拉大腦？拼圖碎片？你從剛才開始到底在說什麼？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"말을 어렵게 빙빙 돌려 말하는 건, 제가 아는 누구랑 똑같군요.","JPN":"話が回りくどいのは、私の知り合いとそっくりですね。","ENG":"The way you keep circling around with complicated explanations is just like someone I know.","TWN":"說話拐彎抹角，這點簡直和我認識的某個人一模一樣。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 제가 조금 불친절했나요?","JPN":"はは、僕の説明が少し不親切でしたか？","ENG":"Haha, was I being a bit unkind?","TWN":"哈哈，是我說得太難懂了嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이곳에 발을 들였을 때, 당신은 어떤 위화감을 느꼈을 겁니다.","JPN":"ここに足を踏み入れた時、あなたは何らかの違和感を覚えたはずです。","ENG":"When you stepped into this place, you must have felt a sense of unease.","TWN":"當你踏進這裡時，應該會感受到某種違和感吧。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};